// The bodyweight-band STRENGTH-STANDARDS dataset, loaded onto the curated-dataset
// framework (issue #860 Track B). Copies the fitness-norms.ts shape: import the envelope
// JSON (generated by scripts/gen-strength-standards.ts), validate it once with
// loadDataset(), and expose the lift ENTRIES + a name→LiftStandards map the pure lookup
// consumes. Identity is the canonical lift `name` (nameStrategy) — one entry per lift.
// The registry lists this for the linter; lib/strength-standards.ts is the pure
// standing / level lookup over these entries. Pure — no DB, no network.

import rawStandards from "./data/strength-standards.json";
import { loadDataset } from "./loader";
import { nameStrategy } from "./matcher";
import type {
  StrengthStandardEntry,
  LiftStandards,
} from "@/scripts/gen-strength-standards";

export type {
  StrengthStandardEntry,
  LiftStandards,
  SexStandards,
  StandardBand,
  StrengthLevelKey,
} from "@/scripts/gen-strength-standards";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const strengthStandardsDataset =
  loadDataset<StrengthStandardEntry>(rawStandards);

// Identity strategy: the canonical lift `name` (case-folded). For the linter/harness —
// each entry carries a unique name, so identity resolves and an unknown name refuses.
export const strengthStandardNameStrategy = nameStrategy;

// The lift entries (curated order) the pure lookup consumes.
export const STRENGTH_STANDARD_ENTRIES: StrengthStandardEntry[] =
  strengthStandardsDataset.entries;

// A name→LiftStandards map rebuilt from the entries, keyed by the EXACT canonical lift
// name (byte-for-byte, so the pure lookup's `LIFTS[name]` / Object.keys / Object.entries
// behave exactly as they did over the old `{ lifts }` map). One source of truth for the
// shape.
export const STRENGTH_STANDARD_LIFTS_MAP: Record<string, LiftStandards> =
  Object.fromEntries(
    STRENGTH_STANDARD_ENTRIES.map((e) => {
      const { name, ...standards } = e;
      return [name, standards as LiftStandards];
    })
  );
